#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn count_matches_table() {
        assert_eq!(INPUT_SOURCES.len(), INPUT_SOURCES_COUNT);
    }

    #[test]
    fn all_paths_have_canonical_prefix() {
        for path in INPUT_SOURCES {
            assert!(path.starts_with("vendor/linux/drivers/input/"), "{path}");
            assert!(path.ends_with(".c"));
        }
    }
}
